// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

interface IHospitalRegistry {
    function isHospitalAdmin(uint256 _hospitalId, address _account) external view returns (bool);
    function hospitalExists(uint256 _hospitalId) external view returns (bool);
}

contract Doctor {
    IHospitalRegistry public immutable hospitalContract;
    uint256 public doctorCount;

    struct DoctorInfo {
        uint256 doctorId;
        string name;
        string specialisation;
        string phone;
        string postalAddress;
        uint256 hospitalId;
        address wallet;
        bool exists;
    }

    mapping(uint256 => DoctorInfo) private doctors;
    mapping(address => uint256) private doctorIdByWallet;
    uint256[] private doctorIds;

    event DoctorRegistered(
        uint256 indexed doctorId,
        string name,
        uint256 indexed hospitalId,
        address indexed wallet
    );

    modifier onlyHospitalAdmin(uint256 _hospitalId) {
        require(
            hospitalContract.isHospitalAdmin(_hospitalId, msg.sender),
            "Only hospital admin can register doctor"
        );
        _;
    }

    /// @notice Stores the hospital registry contract address used for access checks.
    constructor(address _hospitalContractAddress) {
        require(_hospitalContractAddress != address(0), "Hospital contract address is required");
        hospitalContract = IHospitalRegistry(_hospitalContractAddress);
    }

    /// @notice Registers a doctor profile under a hospital.
    /// @dev Only the admin of the specified hospital can register doctors for that hospital.
    function registerDoctor(
        uint256 _doctorId,
        string calldata _name,
        string calldata _specialisation,
        string calldata _phone,
        string calldata _postalAddress,
        uint256 _hospitalId,
        address _doctorWallet
    ) external onlyHospitalAdmin(_hospitalId) {
        require(_doctorId > 0, "Doctor ID must be greater than zero");
        require(bytes(_name).length > 0, "Doctor name is required");
        require(_doctorWallet != address(0), "Doctor wallet is required");
        require(hospitalContract.hospitalExists(_hospitalId), "Hospital does not exist");
        require(!doctors[_doctorId].exists, "Doctor already registered");
        require(doctorIdByWallet[_doctorWallet] == 0, "Wallet already mapped to doctor");

        doctors[_doctorId] = DoctorInfo({
            doctorId: _doctorId,
            name: _name,
            specialisation: _specialisation,
            phone: _phone,
            postalAddress: _postalAddress,
            hospitalId: _hospitalId,
            wallet: _doctorWallet,
            exists: true
        });

        doctorIdByWallet[_doctorWallet] = _doctorId;
        doctorIds.push(_doctorId);
        doctorCount += 1;

        emit DoctorRegistered(_doctorId, _name, _hospitalId, _doctorWallet);
    }

    /// @notice Returns the complete details for a doctor ID.
    function getDoctorDetails(
        uint256 _doctorId
    )
        external
        view
        returns (
            uint256 doctorId,
            string memory name,
            string memory specialisation,
            string memory phone,
            string memory postalAddress,
            uint256 hospitalId,
            address wallet,
            bool exists
        )
    {
        DoctorInfo storage doctorInfo = doctors[_doctorId];
        require(doctorInfo.exists, "Doctor not found");

        return (
            doctorInfo.doctorId,
            doctorInfo.name,
            doctorInfo.specialisation,
            doctorInfo.phone,
            doctorInfo.postalAddress,
            doctorInfo.hospitalId,
            doctorInfo.wallet,
            doctorInfo.exists
        );
    }

    /// @notice Gets doctor ID assigned to a wallet address.
    function getDoctorIdByWallet(address _wallet) external view returns (uint256) {
        return doctorIdByWallet[_wallet];
    }

    /// @notice Checks whether a doctor ID is registered.
    function isDoctorRegistered(uint256 _doctorId) external view returns (bool) {
        return doctors[_doctorId].exists;
    }

    /// @notice Returns all registered doctor IDs.
    function getDoctorIds() external view returns (uint256[] memory) {
        return doctorIds;
    }
}
